document.querySelector("#html2canvas").onload=function(){html2canvas(document.querySelector(".mainBlock"),{onrendered:function(e){var t=e.toDataURL();document.getElementById("resultMain").src=t}}),html2canvas(document.querySelector(".reportBlock"),{onrendered:function(e){var t=e.toDataURL();document.getElementById("resultReport").src=t}}),html2canvas(document.querySelector("#results"),{onrendered:function(e){var t=e.toDataURL();document.getElementById("imgDownload").href=t}})};